import React, { useState, useEffect, useContext } from 'react';
import { useParams, Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import LoadingSpinner from '../components/common/LoadingSpinner';
import MovieCard from '../components/movies/MovieCard';
import { getMovieDetails } from '../services/movieService';
import { rateMovie, checkUserRating } from '../services/ratingService';
import { getSimilarMovies } from '../services/recommendationService';
import { Star, Heart, Share2, Play, Calendar, Clock, Users, ArrowLeft, X, ChevronRight, Sparkles, Eye, MessageSquare } from 'lucide-react';

const MovieDetailsPage = () => {
  const { movieId } = useParams();
  const { user, isAuthenticated } = useContext(AuthContext);
  const [movie, setMovie] = useState(null);
  const [similarMovies, setSimilarMovies] = useState([]);
  const [userRating, setUserRating] = useState(null);
  const [newRating, setNewRating] = useState(0);
  const [review, setReview] = useState('');
  const [hoverRating, setHoverRating] = useState(0);
  const [loading, setLoading] = useState(true);
  const [ratingLoading, setRatingLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showRatingForm, setShowRatingForm] = useState(false);
  const [isWatchlisted, setIsWatchlisted] = useState(false);

  // Enhanced debugging
  console.log('🎬 MovieDetailsPage render:', {
    movieId,
    movieIdType: typeof movieId,
    movie: movie ? { id: movie.id, title: movie.title } : null,
    loading,
    error,
    isAuthenticated,
    user: user?.username,
    urlParams: window.location.pathname
  });

  useEffect(() => {
    console.log('🔄 useEffect triggered - movieId:', movieId);

    if (movieId && movieId !== 'undefined' && movieId !== 'null') {
      console.log('✅ Valid movieId, fetching data...');
      fetchMovieData();
    } else {
      console.error('❌ Invalid movieId:', movieId);
      setError('Invalid movie ID provided');
      setLoading(false);
    }
  }, [movieId]);

  useEffect(() => {
    if (isAuthenticated && movieId && movieId !== 'undefined' && movieId !== 'null') {
      console.log('🔄 Auth changed, fetching user rating...');
      fetchUserRating();
    }
  }, [isAuthenticated, movieId]);

  const fetchMovieData = async () => {
    if (!movieId || movieId === 'undefined' || movieId === 'null') {
      console.error('❌ fetchMovieData: Invalid movieId:', movieId);
      setError('Invalid movie ID provided');
      setLoading(false);
      return;
    }

    console.log('🚀 fetchMovieData: Starting for movieId:', movieId, typeof movieId);
    setLoading(true);
    setError(null);
    setMovie(null);

    try {
      const numericMovieId = isNaN(movieId) ? movieId : parseInt(movieId, 10);
      console.log('🔢 Using movieId:', numericMovieId, typeof numericMovieId);

      console.log('📞 Calling getMovieDetails with:', numericMovieId);
      const movieData = await getMovieDetails(numericMovieId);
      console.log('📊 Movie details response:', movieData);

      if (!movieData) {
        throw new Error('No movie data returned from API');
      }

      let processedMovieData = movieData;

      if (movieData.movie && !movieData.id) {
        processedMovieData = movieData.movie;
        console.log('📦 Unwrapped movie data from response');
      }

      if (movieData.data && !movieData.id) {
        processedMovieData = movieData.data;
        console.log('📦 Unwrapped movie data from data property');
      }

      if (!processedMovieData.id && !processedMovieData.title) {
        console.error('❌ Invalid movie data structure:', processedMovieData);
        throw new Error('Invalid movie data received from server');
      }

      if (processedMovieData.id) {
        processedMovieData.id = parseInt(processedMovieData.id, 10);
      }

      setMovie(processedMovieData);
      console.log('✅ Movie details set successfully:', processedMovieData.title);

      try {
        console.log('📞 Calling getSimilarMovies with:', numericMovieId);
        const similarData = await getSimilarMovies(numericMovieId, 8);
        console.log('📊 Similar movies response:', similarData);

        let similarMoviesArray = [];

        if (similarData?.similar_movies && Array.isArray(similarData.similar_movies)) {
          similarMoviesArray = similarData.similar_movies;
        } else if (Array.isArray(similarData)) {
          similarMoviesArray = similarData;
        } else if (similarData?.data && Array.isArray(similarData.data)) {
          similarMoviesArray = similarData.data;
        }

        setSimilarMovies(similarMoviesArray);
        console.log('✅ Similar movies set:', similarMoviesArray.length, 'movies');

      } catch (similarError) {
        console.warn('⚠️ Failed to fetch similar movies (non-critical):', similarError.message);
        setSimilarMovies([]);
      }

    } catch (error) {
      console.error('💥 Error in fetchMovieData:', error);
      console.error('💥 Error details:', {
        message: error.message,
        response: error.response?.data,
        status: error.response?.status,
        url: error.config?.url,
        method: error.config?.method
      });

      let errorMessage = 'Failed to load movie details. Please try again.';

      if (error.response?.status === 404) {
        errorMessage = `Movie with ID "${movieId}" not found. It may have been removed or the link is incorrect.`;
      } else if (error.response?.status === 403) {
        errorMessage = 'Access denied. You may need to log in to view this movie.';
      } else if (error.response?.status >= 500) {
        errorMessage = 'Server error. Please try again later.';
      } else if (error.name === 'NetworkError' || !navigator.onLine) {
        errorMessage = 'No internet connection. Please check your connection and try again.';
      } else if (error.message.includes('Invalid movie ID')) {
        errorMessage = `Invalid movie ID: "${movieId}". Please check the URL.`;
      }

      setError(errorMessage);
      setMovie(null);
    } finally {
      console.log('✅ fetchMovieData completed, setting loading to false');
      setLoading(false);
    }
  };

  const fetchUserRating = async () => {
    if (!movieId || !isAuthenticated || movieId === 'undefined' || movieId === 'null') {
      console.log('⏭️ Skipping fetchUserRating - missing requirements');
      return;
    }

    try {
      console.log('📞 Fetching user rating for movie:', movieId);
      const numericMovieId = isNaN(movieId) ? movieId : parseInt(movieId, 10);
      const ratingData = await checkUserRating(numericMovieId);
      console.log('📊 User rating response:', ratingData);

      if (ratingData?.has_rated && ratingData?.rating) {
        setUserRating(ratingData.rating);
        setNewRating(ratingData.rating.rating || 0);
        setReview(ratingData.rating.review || '');
        console.log('✅ User rating set:', ratingData.rating);
      } else {
        console.log('ℹ️ User has not rated this movie');
        setUserRating(null);
        setNewRating(0);
        setReview('');
      }
    } catch (error) {
      console.warn('⚠️ Error fetching user rating (non-critical):', error.message);
      setUserRating(null);
    }
  };

  const handleRatingSubmit = async (e) => {
    e.preventDefault();
    if (!newRating || newRating < 1 || newRating > 5) {
      alert('Please select a rating between 1 and 5 stars');
      return;
    }

    setRatingLoading(true);

    try {
      const numericMovieId = isNaN(movieId) ? movieId : parseInt(movieId, 10);
      const ratingData = await rateMovie({
        movie_id: numericMovieId,
        rating: newRating,
        review: review.trim()
      });

      setUserRating(ratingData.rating);
      setShowRatingForm(false);

      await fetchMovieData();

      alert('Rating saved successfully!');
    } catch (error) {
      console.error('Error saving rating:', error);
      alert('Failed to save rating. Please try again.');
    } finally {
      setRatingLoading(false);
    }
  };

  const renderStars = (rating, interactive = false, size = 'medium') => {
    const stars = [];
    const maxStars = 5;
    const numericRating = parseFloat(rating) || 0;
    const currentRating = interactive ? (hoverRating || newRating) : numericRating;

    const sizeClasses = {
      small: 'w-4 h-4',
      medium: 'w-5 h-5',
      large: 'w-8 h-8'
    };

    for (let i = 1; i <= maxStars; i++) {
      const filled = i <= currentRating;
      stars.push(
        <button
          key={i}
          type="button"
          className={`${sizeClasses[size]} ${interactive ? 'cursor-pointer hover:scale-110 transition-all duration-300' : 'cursor-default'} ${filled ? 'text-amber-400 drop-shadow-[0_0_8px_rgba(251,191,36,0.6)]' : 'text-zinc-600'} focus:outline-none`}
          onClick={interactive ? () => setNewRating(i) : undefined}
          onMouseEnter={interactive ? () => setHoverRating(i) : undefined}
          onMouseLeave={interactive ? () => setHoverRating(0) : undefined}
          disabled={!interactive}
        >
          <Star className={`w-full h-full ${filled ? 'fill-current' : ''}`} />
        </button>
      );
    }

    return <div className="flex items-center gap-1">{stars}</div>;
  };

  const formatDate = (dateString) => {
    if (!dateString) return '';
    try {
      const date = new Date(dateString);
      return date.toLocaleDateString('en-US', {
        year: 'numeric',
        month: 'long',
        day: 'numeric'
      });
    } catch (error) {
      console.warn('Error formatting date:', dateString);
      return dateString;
    }
  };

  if (loading) {
    console.log('🔄 Showing loading spinner');
    return (
      <div className="min-h-screen bg-gradient-to-br from-zinc-950 via-zinc-900 to-zinc-950 flex flex-col items-center justify-center relative overflow-hidden">
        {/* Animated background elements */}
        <div className="absolute inset-0 overflow-hidden">
          <div className="absolute top-1/4 left-1/4 w-72 h-72 bg-violet-500/20 rounded-full blur-3xl animate-pulse"></div>
          <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-blue-500/20 rounded-full blur-3xl animate-pulse delay-1000"></div>
        </div>

        <div className="relative z-10 flex flex-col items-center">
          <div className="relative">
            <div className="w-20 h-20 border-4 border-violet-500/30 border-t-violet-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 w-20 h-20 border-4 border-blue-500/30 border-b-blue-500 rounded-full animate-spin animation-delay-150"></div>
          </div>
          <div className="text-center mt-8">
            <p className="text-white text-xl font-medium">Loading movie details...</p>
            <p className="text-zinc-400 text-sm mt-2">Please wait while we fetch the information</p>
            {process.env.NODE_ENV === 'development' && (
              <p className="text-zinc-600 text-xs mt-2">
                Movie ID: {movieId} ({typeof movieId})
              </p>
            )}
          </div>
        </div>
      </div>
    );
  }

  if (error) {
    console.log('❌ Showing error state:', error);
    return (
      <div className="min-h-screen bg-gradient-to-br from-zinc-950 via-zinc-900 to-zinc-950 flex items-center justify-center relative overflow-hidden">
        {/* Background elements */}
        <div className="absolute inset-0 overflow-hidden">
          <div className="absolute top-1/3 left-1/3 w-64 h-64 bg-red-500/10 rounded-full blur-3xl"></div>
          <div className="absolute bottom-1/3 right-1/3 w-80 h-80 bg-orange-500/10 rounded-full blur-3xl"></div>
        </div>

        <div className="max-w-lg mx-auto text-center relative z-10">
          <div className="bg-white/5 backdrop-blur-xl rounded-3xl p-8 border border-white/10 shadow-2xl">
            <div className="w-16 h-16 bg-gradient-to-br from-red-500 to-orange-500 rounded-2xl flex items-center justify-center mx-auto mb-6">
              <X className="w-8 h-8 text-white" />
            </div>

            <h2 className="text-3xl font-bold text-white mb-4">Something went wrong</h2>
            <p className="text-zinc-400 mb-8 leading-relaxed">{error}</p>

            <div className="flex gap-4 justify-center">
              <button 
                onClick={() => {
                  console.log('🔄 Retrying movie data fetch');
                  fetchMovieData();
                }}
                className="bg-gradient-to-r from-violet-600 to-blue-600 hover:from-violet-700 hover:to-blue-700 text-white px-6 py-3 rounded-xl font-semibold transition-all duration-300 transform hover:scale-105 shadow-lg"
              >
                🔄 Try Again
              </button>
              <Link 
                to="/movies" 
                className="bg-white/10 hover:bg-white/20 text-white px-6 py-3 rounded-xl font-semibold transition-all duration-300 flex items-center gap-2 border border-white/20"
              >
                <ArrowLeft className="w-4 h-4" />
                Browse Movies
              </Link>
            </div>

            {process.env.NODE_ENV === 'development' && (
              <details className="mt-8 text-left bg-zinc-800/50 rounded-xl p-4">
                <summary className="cursor-pointer font-bold text-white text-sm flex items-center gap-2">
                  <Eye className="w-4 h-4" />
                  Debug Info (Development Only)
                </summary>
                <div className="mt-3 text-xs text-zinc-400 font-mono space-y-1">
                  <p><strong>Movie ID:</strong> {movieId} ({typeof movieId})</p>
                  <p><strong>URL:</strong> {window.location.pathname}</p>
                  <p><strong>Error:</strong> {error}</p>
                  <p><strong>Auth Status:</strong> {isAuthenticated ? 'Authenticated' : 'Not authenticated'}</p>
                  <p><strong>User:</strong> {user?.username || 'None'}</p>
                  <p><strong>Movie State:</strong> {movie ? 'Has movie data' : 'No movie data'}</p>
                </div>
              </details>
            )}
          </div>
        </div>
      </div>
    );
  }

  if (!movie) {
    console.log('❌ No movie data available');
    return (
      <div className="min-h-screen bg-gradient-to-br from-zinc-950 via-zinc-900 to-zinc-950 flex items-center justify-center">
        <div className="max-w-lg mx-auto text-center">
          <div className="bg-white/5 backdrop-blur-xl rounded-3xl p-8 border border-white/10 shadow-2xl">
            <div className="w-16 h-16 bg-gradient-to-br from-zinc-600 to-zinc-700 rounded-2xl flex items-center justify-center mx-auto mb-6">
              <Eye className="w-8 h-8 text-white" />
            </div>

            <h2 className="text-3xl font-bold text-white mb-4">Movie not found</h2>
            <p className="text-zinc-400 mb-8">The movie you're looking for doesn't exist or couldn't be loaded.</p>

            <div className="flex gap-4 justify-center">
              <button 
                onClick={() => {
                  console.log('🔄 Retrying movie data fetch');
                  fetchMovieData();
                }}
                className="bg-gradient-to-r from-violet-600 to-blue-600 hover:from-violet-700 hover:to-blue-700 text-white px-6 py-3 rounded-xl font-semibold transition-all duration-300"
              >
                🔄 Try Again
              </button>
              <Link 
                to="/movies" 
                className="bg-white/10 hover:bg-white/20 text-white px-6 py-3 rounded-xl font-semibold transition-all duration-300 flex items-center gap-2 border border-white/20"
              >
                <ArrowLeft className="w-4 h-4" />
                Browse Movies
              </Link>
            </div>
          </div>
        </div>
      </div>
    );
  }

  console.log('✅ Rendering movie details for:', movie.title);

  return (
    <div className="min-h-screen bg-gradient-to-br from-zinc-950 via-zinc-900 to-zinc-950 relative overflow-hidden">
      {/* Animated background elements */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-violet-500/10 rounded-full blur-3xl animate-pulse"></div>
        <div className="absolute bottom-1/4 right-1/4 w-80 h-80 bg-blue-500/10 rounded-full blur-3xl animate-pulse delay-1000"></div>
        <div className="absolute top-3/4 left-3/4 w-64 h-64 bg-purple-500/10 rounded-full blur-3xl animate-pulse delay-2000"></div>
      </div>

      {/* Hero Section */}
      <div className="relative min-h-screen flex items-center">
        {/* Background */}
        <div className="absolute inset-0 z-0">
          <img
            src={movie.poster_url || '/placeholder-movie.jpg'}
            alt={movie.title}
            className="w-full h-full object-cover opacity-20"
            onError={(e) => {
              console.warn('⚠️ Backdrop image failed to load:', movie.poster_url);
              e.target.src = '/placeholder-movie.jpg';
            }}
          />
          <div className="absolute inset-0 bg-gradient-to-r from-zinc-950/95 via-zinc-950/80 to-transparent" />
          <div className="absolute inset-0 bg-gradient-to-t from-zinc-950 via-transparent to-zinc-950/50" />
        </div>

        {/* Back Button */}
        <Link 
          to="/movies"
          className="fixed top-6 left-6 z-50 flex items-center gap-2 px-6 py-3 bg-black/40 backdrop-blur-xl rounded-full text-white hover:bg-black/60 transition-all duration-300 border border-white/10"
        >
          <ArrowLeft className="w-4 h-4" />
          <span className="font-medium">Back</span>
        </Link>

        {/* Content */}
        <div className="relative z-10 max-w-7xl mx-auto px-6 py-20">
          <div className="grid lg:grid-cols-5 gap-12 items-start">
            {/* Poster */}
            <div className="lg:col-span-2">
              <div className="relative group">
                <div className="absolute inset-0 bg-gradient-to-b from-violet-500/20 to-blue-500/20 rounded-3xl blur-xl transform group-hover:scale-105 transition-transform duration-700"></div>
                <img
                  src={movie.poster_url || '/placeholder-movie.jpg'}
                  alt={movie.title}
                  className="relative w-full max-w-md mx-auto rounded-3xl shadow-2xl transform group-hover:scale-[1.02] transition-transform duration-700 border border-white/10"
                  onError={(e) => {
                    console.warn('⚠️ Poster image failed to load:', movie.poster_url);
                    e.target.src = '/placeholder-movie.jpg';
                  }}
                />

                {/* Play Button Overlay */}
                <button className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-500">
                  <div className="w-20 h-20 bg-white/20 backdrop-blur-xl rounded-full flex items-center justify-center hover:bg-white/30 transition-colors duration-300 border border-white/20">
                    <Play className="w-8 h-8 text-white ml-1" />
                  </div>
                </button>
              </div>
            </div>

            {/* Movie Info */}
            <div className="lg:col-span-3 text-white space-y-8">
              <div>
                <h1 className="text-5xl lg:text-7xl font-bold bg-gradient-to-r from-white via-violet-200 to-blue-200 bg-clip-text text-transparent mb-6 leading-tight">
                  {movie.title}
                </h1>

                <div className="flex items-center gap-6 text-lg text-zinc-400 mb-8 flex-wrap">
                  {movie.year && (
                    <div className="flex items-center gap-2 bg-white/5 px-3 py-2 rounded-lg backdrop-blur-xl border border-white/10">
                      <Calendar className="w-5 h-5 text-violet-400" />
                      <span className="font-medium">{movie.year}</span>
                    </div>
                  )}
                  {movie.runtime && (
                    <div className="flex items-center gap-2 bg-white/5 px-3 py-2 rounded-lg backdrop-blur-xl border border-white/10">
                      <Clock className="w-5 h-5 text-blue-400" />
                      <span className="font-medium">{movie.runtime} min</span>
                    </div>
                  )}
                  <div className="flex items-center gap-2 bg-white/5 px-3 py-2 rounded-lg backdrop-blur-xl border border-white/10">
                    <Users className="w-5 h-5 text-emerald-400" />
                    <span className="font-medium">{movie.rating_count || 0} ratings</span>
                  </div>
                </div>
              </div>

              {/* Rating */}
              <div className="flex items-center gap-6 p-6 bg-white/5 backdrop-blur-xl rounded-2xl border border-white/10">
                <div className="flex items-center gap-4">
                  {renderStars(movie.avg_rating)}
                  <span className="text-3xl font-bold text-white">
                    {movie.avg_rating ? parseFloat(movie.avg_rating).toFixed(1) : 'N/A'}
                  </span>
                  <span className="text-zinc-400 text-lg">/ 5</span>
                </div>
                <div className="flex items-center gap-2 text-sm text-zinc-400">
                  <Sparkles className="w-4 h-4" />
                  <span>Community Rating</span>
                </div>
              </div>

              {/* Genres */}
              {movie.genres && Array.isArray(movie.genres) && movie.genres.length > 0 && (
                <div className="flex flex-wrap gap-3">
                  {movie.genres.map((genre, index) => (
                    <Link
                      key={`${genre}-${index}`}
                      to={`/movies?genre=${encodeURIComponent(genre)}`}
                      className="px-4 py-2 bg-gradient-to-r from-violet-500/20 to-blue-500/20 backdrop-blur-xl rounded-full text-sm font-medium hover:from-violet-500/30 hover:to-blue-500/30 transition-all duration-300 border border-white/10 hover:border-white/20"
                    >
                      {genre}
                    </Link>
                  ))}
                </div>
              )}

              {/* Plot */}
              {movie.plot && (
                <div className="p-6 bg-white/5 backdrop-blur-xl rounded-2xl border border-white/10">
                  <p className="text-xl leading-relaxed text-zinc-200 max-w-3xl">
                    {movie.plot}
                  </p>
                </div>
              )}

              {/* Action Buttons */}
              <div className="flex gap-4 pt-6 flex-wrap">
                {isAuthenticated && (
                  <button
                    onClick={() => setShowRatingForm(true)}
                    className="flex items-center gap-3 bg-gradient-to-r from-violet-600 to-blue-600 hover:from-violet-700 hover:to-blue-700 px-8 py-4 rounded-2xl font-semibold transition-all duration-300 transform hover:scale-105 shadow-lg hover:shadow-violet-500/25"
                  >
                    <Star className="w-5 h-5" />
                    {userRating ? 'Update Rating' : 'Rate Movie'}
                  </button>
                )}

                <button
                  onClick={() => setIsWatchlisted(!isWatchlisted)}
                  className={`flex items-center gap-3 px-8 py-4 rounded-2xl font-semibold transition-all duration-300 transform hover:scale-105 shadow-lg ${
                    isWatchlisted
                      ? 'bg-gradient-to-r from-red-600 to-pink-600 hover:from-red-700 hover:to-pink-700 hover:shadow-red-500/25'
                      : 'bg-white/10 hover:bg-white/20 backdrop-blur-xl border border-white/10 hover:border-white/20'
                  }`}
                >
                  <Heart className={`w-5 h-5 ${isWatchlisted ? 'fill-current' : ''}`} />
                  {isWatchlisted ? 'Remove from Watchlist' : 'Add to Watchlist'}
                </button>

                <button className="flex items-center gap-3 bg-white/10 hover:bg-white/20 backdrop-blur-xl px-8 py-4 rounded-2xl font-semibold transition-all duration-300 transform hover:scale-105 shadow-lg border border-white/10 hover:border-white/20">
                  <Share2 className="w-5 h-5" />
                  Share
                </button>
              </div>

              {/* User's Rating Display */}
              {userRating && (
                <div className="bg-gradient-to-r from-violet-500/10 to-blue-500/10 backdrop-blur-xl rounded-2xl p-6 border border-violet-500/20">
                  <h3 className="text-xl font-semibold mb-4 flex items-center gap-2">
                    <MessageSquare className="w-5 h-5 text-violet-400" />
                    Your Rating
                  </h3>
                  <div className="flex items-center gap-4 mb-4">
                    {renderStars(userRating.rating)}
                    <span className="text-lg font-semibold">{userRating.rating}/5</span>
                  </div>
                  {userRating.review && (
                    <div className="bg-white/5 rounded-xl p-4 border border-white/10">
                      <p className="text-zinc-300 italic leading-relaxed">"{userRating.review}"</p>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Rating Form Modal */}
      {showRatingForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-xl">
          <div className="bg-zinc-900/95 backdrop-blur-xl rounded-3xl p-8 w-full max-w-md relative border border-white/10 shadow-2xl animate-in fade-in zoom-in-95 duration-300">
            <button
              onClick={() => setShowRatingForm(false)}
              className="absolute top-6 right-6 p-2 hover:bg-white/10 rounded-xl transition-colors duration-200"
            >
              <X className="w-5 h-5 text-white" />
            </button>

            <h3 className="text-2xl font-bold mb-8 text-white">{userRating ? 'Update Your Rating' : 'Rate This Movie'}</h3>

            <div className="space-y-8">
              <div className="text-center">
                <label className="block text-zinc-400 font-medium mb-6">Your Rating:</label>
                <div className="flex justify-center mb-4">
                  {renderStars(newRating, true, 'large')}
                </div>
                <span className="text-xl font-semibold text-white">
                  {newRating > 0 ? `${newRating}/5 stars` : 'Select a rating'}
                </span>
              </div>

              <div>
                <label htmlFor="review" className="block text-sm font-medium text-zinc-400 mb-3">
                  Review (optional):
                </label>
                <textarea
                  id="review"
                  value={review}
                  onChange={(e) => setReview(e.target.value)}
                  placeholder="Share your thoughts about this movie..."
                  rows="4"
                  className="w-full px-4 py-3 bg-white/10 backdrop-blur-xl border border-white/20 rounded-xl text-white placeholder-zinc-500 focus:ring-2 focus:ring-violet-500 focus:border-transparent resize-none transition-all duration-300"
                  maxLength="1000"
                />
                <div className="flex justify-between items-center mt-2">
                  <span className="text-sm text-zinc-500">{review.length}/1000</span>
                </div>
              </div>

              <div className="flex gap-4 pt-4">
                <button
                  type="button"
                  onClick={() => setShowRatingForm(false)}
                  className="flex-1 py-3 border border-white/20 rounded-xl font-semibold hover:bg-white/10 transition-all duration-300 text-white"
                  disabled={ratingLoading}
                >
                  Cancel
                </button>
                <button
                  type="button"
                  onClick={handleRatingSubmit}
                  disabled={ratingLoading || newRating === 0}
                  className="flex-1 py-3 bg-gradient-to-r from-violet-600 to-blue-600 text-white font-semibold rounded-xl hover:from-violet-700 hover:to-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-300 shadow-lg hover:shadow-violet-500/25"
                >
                  {ratingLoading ? 'Saving...' : 'Save Rating'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Reviews Section */}
      {movie.reviews && Array.isArray(movie.reviews) && movie.reviews.length > 0 && (
        <section className="py-20 px-6 relative z-10">
          <div className="max-w-7xl mx-auto">
            <h2 className="text-4xl font-bold text-white mb-12 flex items-center gap-3">
              <MessageSquare className="w-8 h-8 text-violet-400" />
              Recent Reviews
            </h2>
            <div className="grid gap-6">
              {movie.reviews.slice(0, 5).map((review, index) => (
                <div
                  key={`review-${index}`}
                  className="bg-white/5 backdrop-blur-xl rounded-2xl p-8 border border-white/10 hover:bg-white/10 hover:border-white/20 transition-all duration-300"
                >
                  <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-gradient-to-br from-violet-600 to-blue-600 rounded-full flex items-center justify-center font-bold text-white shadow-lg">
                        {(review.username || 'Anonymous').charAt(0).toUpperCase()}
                      </div>
                      <div>
                        <span className="font-semibold text-white text-lg">{review.username || 'Anonymous'}</span>
                        <span className="block text-sm text-zinc-400">
                          {formatDate(review.timestamp || review.created_at)}
                        </span>
                      </div>
                    </div>
                    <div className="flex items-center gap-3 bg-white/5 px-4 py-2 rounded-xl border border-white/10">
                      {renderStars(review.rating, false, 'small')}
                      <span className="text-white font-semibold">{review.rating}/5</span>
                    </div>
                  </div>
                  {review.review && (
                    <div className="bg-white/5 rounded-xl p-4 border border-white/10">
                      <p className="text-zinc-300 leading-relaxed text-lg italic">"{review.review}"</p>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </section>
      )}

      {/* Similar Movies Section */}
      {similarMovies && similarMovies.length > 0 && (
        <section className="py-20 px-6 relative z-10">
          <div className="max-w-7xl mx-auto">
            <div className="flex items-center justify-between mb-12">
              <h2 className="text-4xl font-bold text-white flex items-center gap-3">
                <Sparkles className="w-8 h-8 text-violet-400" />
                Similar Movies
              </h2>
              <button className="flex items-center gap-2 text-violet-400 hover:text-violet-300 transition-colors duration-300 bg-white/5 px-4 py-2 rounded-xl border border-white/10 hover:border-white/20">
                View All
                <ChevronRight className="w-5 h-5" />
              </button>
            </div>
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-8">
              {similarMovies.map(similarMovie => (
                <MovieCard key={`similar-${similarMovie.id}`} movie={similarMovie} />
              ))}
            </div>
          </div>
        </section>
      )}

      {/* Back Navigation */}
      <div className="px-6 pb-12 relative z-10">
        <div className="max-w-7xl mx-auto">
          <Link 
            to="/movies" 
            className="inline-flex items-center gap-3 bg-white/10 hover:bg-white/20 backdrop-blur-xl text-white px-8 py-4 rounded-2xl font-semibold transition-all duration-300 transform hover:scale-105 border border-white/10 hover:border-white/20 shadow-lg"
          >
            <ArrowLeft className="w-5 h-5" />
            Back to Movies
          </Link>
        </div>
      </div>
    </div>
  );
};
